<?php
namespace App\Controllers;
use App\Core\Controller; use App\Models\BaseCatalog;
class MovimientoController extends Controller {
 public function entregas():void{$this->requirePermission('Entrega de materiales');$m=new BaseCatalog;$rows=$m->fetchAll('SELECT e.*, CONCAT(r.nombre," ",r.apellido) receptor, CONCAT(a.nombre," ",a.apellido) entrega FROM entregas_materiales e JOIN usuarios r ON r.id=e.usuario_receptor_id JOIN usuarios a ON a.id=e.usuario_entrega_id ORDER BY e.id DESC');$this->view('entregas/index',compact('rows'));}
 public function recepciones():void{$this->requirePermission('Recepción de materiales');$m=new BaseCatalog;$rows=$m->fetchAll('SELECT r.*, CONCAT(d.nombre," ",d.apellido) devuelve, CONCAT(a.nombre," ",a.apellido) recibe FROM recepciones_materiales r JOIN usuarios d ON d.id=r.usuario_devuelve_id JOIN usuarios a ON a.id=r.usuario_recibe_id ORDER BY r.id DESC');$this->view('recepciones/index',compact('rows'));}
 public function formEntrega():void{$this->requirePermission('Entrega de materiales','crear');$m=new BaseCatalog;$usuarios=$m->all('usuarios','nombre');$materiales=$m->all('materiales','nombre_material');$this->view('entregas/form',compact('usuarios','materiales'));}
 public function formRecepcion():void{$this->requirePermission('Recepción de materiales','crear');$m=new BaseCatalog;$usuarios=$m->all('usuarios','nombre');$detalles=$m->fetchAll('SELECT d.id detalle_id,e.id entrega_id,e.usuario_receptor_id,CONCAT(u.nombre," ",u.apellido) receptor,m.id material_id,m.nombre_material,d.cantidad_disponible FROM entrega_material_detalle d JOIN entregas_materiales e ON e.id=d.entrega_id JOIN usuarios u ON u.id=e.usuario_receptor_id JOIN materiales m ON m.id=d.material_id WHERE e.estado="activa" AND d.cantidad_disponible>0 ORDER BY e.fecha_entrega DESC,e.id DESC,m.nombre_material');$this->view('recepciones/form',compact('usuarios','detalles'));}
 public function saveEntrega():void{verify_csrf();$this->requirePermission('Entrega de materiales','crear');$db=\App\Core\App::db();$db->beginTransaction();try{$m=new BaseCatalog;$m->execSql('INSERT INTO entregas_materiales(usuario_receptor_id,usuario_entrega_id,fecha_entrega,observacion,estado,created_at) VALUES(?,?,?,?,?,NOW())',[$_POST['usuario_receptor_id'],current_user()['id'],$_POST['fecha_entrega'],$_POST['observacion'],'activa']);$eid=(int)$db->lastInsertId();foreach($_POST['material_id']??[] as $i=>$mid){$cant=(float)$_POST['cantidad'][$i]; if($cant<=0)continue; $mat=$m->fetch('SELECT stock_actual FROM materiales WHERE id=? FOR UPDATE',[$mid]); if($cant>$mat['stock_actual']) throw new \RuntimeException('Stock insuficiente'); $after=$mat['stock_actual']-$cant; $m->execSql('UPDATE materiales SET stock_actual=? WHERE id=?',[$after,$mid]); $m->execSql('INSERT INTO entrega_material_detalle(entrega_id,material_id,cantidad_entregada,stock_antes,stock_despues,cantidad_disponible) VALUES(?,?,?,?,?,?)',[$eid,$mid,$cant,$mat['stock_actual'],$after,$cant]); $m->execSql('INSERT INTO kardex_materiales(material_id,tipo_movimiento,cantidad,stock_antes,stock_despues,referencia_tipo,referencia_id,usuario_id,fecha) VALUES(?,?,?,?,?,?,?,?,NOW())',[$mid,'salida_entrega',$cant,$mat['stock_actual'],$after,'entrega',$eid,current_user()['id']]);}$m->audit('Crear','Entrega de materiales',$eid,'Entrega registrada');$db->commit();flash('success','Entrega registrada.');redirect('entregas-materiales');}catch(\Throwable $e){$db->rollBack();flash('error',$e->getMessage());redirect('entregas-materiales/crear');}}
 public function saveRecepcion():void{verify_csrf();$this->requirePermission('Recepción de materiales','crear');$db=\App\Core\App::db();$db->beginTransaction();try{$m=new BaseCatalog;$m->execSql('INSERT INTO recepciones_materiales(usuario_devuelve_id,usuario_recibe_id,fecha_recepcion,observacion,estado,created_at) VALUES(?,?,?,?,?,NOW())',[$_POST['usuario_devuelve_id'],current_user()['id'],$_POST['fecha_recepcion'],$_POST['observacion'],'registrada']);$rid=(int)$db->lastInsertId();$procesados=0;foreach($_POST['detalle_id']??[] as $i=>$detalleId){$cant=(float)($_POST['cantidad'][$i]??0); if($cant<=0)continue;$det=$m->fetch('SELECT d.*,e.usuario_receptor_id,m.stock_actual FROM entrega_material_detalle d JOIN entregas_materiales e ON e.id=d.entrega_id JOIN materiales m ON m.id=d.material_id WHERE d.id=? FOR UPDATE',[$detalleId]); if(!$det) throw new \RuntimeException('Detalle de entrega no encontrado.'); if((int)$det['usuario_receptor_id']!==(int)$_POST['usuario_devuelve_id']) throw new \RuntimeException('El material seleccionado no pertenece al usuario que devuelve.'); if($cant>(float)$det['cantidad_disponible']) throw new \RuntimeException('La cantidad devuelta supera lo pendiente.');$estado=$_POST['estado_material'][$i]??'Bueno';$devuelveStock=in_array($estado,['Bueno','Usado'],true);$stockAntes=(float)$det['stock_actual'];$stockDespues=$devuelveStock?$stockAntes+$cant:$stockAntes;$m->execSql('UPDATE entrega_material_detalle SET cantidad_disponible=cantidad_disponible-? WHERE id=?',[$cant,$detalleId]);if($devuelveStock)$m->execSql('UPDATE materiales SET stock_actual=? WHERE id=?',[$stockDespues,$det['material_id']]);$m->execSql('INSERT INTO recepcion_material_detalle(recepcion_id,material_id,cantidad_devuelta,estado_material,stock_antes,stock_despues) VALUES(?,?,?,?,?,?)',[$rid,$det['material_id'],$cant,$estado,$stockAntes,$stockDespues]);$m->execSql('INSERT INTO kardex_materiales(material_id,tipo_movimiento,cantidad,stock_antes,stock_despues,referencia_tipo,referencia_id,usuario_id,fecha) VALUES(?,?,?,?,?,?,?,?,NOW())',[$det['material_id'],$devuelveStock?'entrada_recepcion':'recepcion_sin_stock',$cant,$stockAntes,$stockDespues,'recepcion',$rid,current_user()['id']]);$m->execSql('UPDATE entregas_materiales e SET estado=IF((SELECT COALESCE(SUM(cantidad_disponible),0) FROM entrega_material_detalle WHERE entrega_id=e.id)<=0,"cerrada",e.estado),updated_at=NOW() WHERE e.id=?',[$det['entrega_id']]);$procesados++;}if(!$procesados) throw new \RuntimeException('Debe ingresar al menos un material con cantidad mayor a cero.');$m->audit('Crear','Recepción de materiales',$rid,'Recepción registrada');$db->commit();flash('success','Recepción registrada.');redirect('recepciones-materiales');}catch(\Throwable $e){$db->rollBack();flash('error',$e->getMessage());redirect('recepciones-materiales/crear');}}
}
